t.script:
                    // Search data
                    var searchData = ;
                    var selectedIndex = -1;
                    var filteredResults = [];

                    function toggleSearch() {
                        var overlay = document.getElementById('commandPalette');
                        var input = document.getElementById('searchInput');

                        if (overlay.style.display === 'none') {
                            overlay.style.display = 'flex';
                            setTimeout(function() { input.focus(); }, 10);
                        } else {
                            overlay.style.display = 'none';
                            input.value = '';
                            clearResults();
                        }
                    }

                    function closeSearch(e) {
                        if (e.target.id === 'commandPalette') {
                            toggleSearch();
                        }
                    }

                    function clearResults() {
                        document.getElementById('searchResults').innerHTML = '';
                        selectedIndex = -1;
                        filteredResults = [];
                    }

                    function performSearch(query) {
                        if (!query) {
                            clearResults();
                            return;
                        }

                        var q = query.toLowerCase();
                        var results = [];

                        for (var i = 0; i < searchData.length; i++) {
                            var item = searchData[i];
                            var score = 0;

                            // Exact match
                            if (item.name.toLowerCase() === q) score += 100;
                            // Starts with
                            else if (item.name.toLowerCase().startsWith(q)) score += 50;
                            // Contains
                            else if (item.name.toLowerCase().includes(q)) score += 25;
                            // Keywords match
                            else if (item.keywords && item.keywords.includes(q)) score += 10;
                            // Description match
                            else if (item.description && item.description.toLowerCase().includes(q)) score += 5;

                            if (score > 0) {
                                results.push({item: item, score: score});
                            }
                        }

                        // Sort by score
                        results.sort(function(a, b) { return b.score - a.score; });
                        filteredResults = results.slice(0, 10);
                        renderResults(filteredResults);
                    }

                    function renderResults(results) {
                        var container = document.getElementById('searchResults');
                        if (results.length === 0) {
                            container.innerHTML = '
Không tìm thấy kết quả';
                            return;
                        }

                        var html = '';
                        for (var i = 0; i < results.length; i++) {
                            var r = results[i].item;
                            var icon = r.type === 'module' ? 'fa-th-large' : 'fa-bars';
                            var selectedClass = i === selectedIndex ? 'selected' : '';

                            html += '' +
                                    '
' +
                                    '
' +
                                    '
' + r.name + '' +
                                    '
' + (r.description || '') + '' +
                                    '' +
                                    '' + r.type + '' +
                                    '';
                        }
                        container.innerHTML = html;
                    }

                    function selectResult(index) {
                        var items = document.querySelectorAll('.result-item');
                        if (items[index]) {
                            items[index].click();
                        }
                    }

                    function navigateResults(direction) {
                        var items = document.querySelectorAll('.result-item');
                        if (items.length === 0) return;

                        if (direction === 'down') {
                            selectedIndex = (selectedIndex + 1) % items.length;
                        } else {
                            selectedIndex = selectedIndex <= 0 ? items.length - 1 : selectedIndex - 1;
                        }

                        items.forEach(function(item, idx) {
                            item.classList.toggle('selected', idx === selectedIndex);
                        });

                        items[selectedIndex].scrollIntoView({block: 'nearest'});
                    }

                    // Event listeners
                    document.addEventListener('DOMContentLoaded', function() {
                        // Clock
                        function updateClock() {
                            var now = new Date();
                            var h = now.getHours().toString().padStart(2,'0');
                            var m = now.getMinutes().toString().padStart(2,'0');
                            var el = document.getElementById('clock');
                            if (el) el.textContent = h + ':' + m;
                        }
                        updateClock();
                        setInterval(updateClock, 1000);

                        // Search input
                        var input = document.getElementById('searchInput');
                        if (input) {
                            input.addEventListener('input', function() {
                                performSearch(this.value);
                            });

                            input.addEventListener('keydown', function(e) {
                                if (e.key === 'ArrowDown') {
                                    e.preventDefault();
                                    navigateResults('down');
                                } else if (e.key === 'ArrowUp') {
                                    e.preventDefault();
                                    navigateResults('up');
                                } else if (e.key === 'Enter') {
                                    e.preventDefault();
                                    if (selectedIndex >= 0) {
                                        selectResult(selectedIndex);
                                    } else if (filteredResults.length > 0) {
                                        window.location.href = filteredResults[0].item.url;
                                    }
                                }
                            });
                        }

                        // Keyboard shortcut Ctrl+K
                        document.addEventListener('keydown', function(e) {
                            if ((e.ctrlKey || e.metaKey) && e.key === 'k') {
                                e.preventDefault();
                                toggleSearch();
                            } else if (e.key === 'Escape') {
                                var overlay = document.getElementById('commandPalette');
                                if (overlay.style.display !== 'none') {
                                    toggleSearch();
                                }
                            }
                        });
                    });
